dashboard.definition:
{
  "title": "Scenario - Data Exfiltration",
  "description": "APT-style data exfiltration -- 14-day attack spanning reconnaissance, initial access, lateral movement, persistence, and exfiltration",
  "dataSources": {
    "ds_kpi_events": {
      "type": "ds.search",
      "name": "Total Exfil Events",
      "options": {
        "query": "index=fake_tshrt demo_id exfil | stats count as total"
      }
    },
    "ds_kpi_sourcetypes": {
      "type": "ds.search",
      "name": "Distinct Sourcetypes",
      "options": {
        "query": "index=fake_tshrt demo_id exfil | stats dc(sourcetype) as total"
      }
    },
    "ds_kpi_hosts": {
      "type": "ds.search",
      "name": "Distinct Hosts",
      "options": {
        "query": "index=fake_tshrt demo_id exfil | stats dc(host) as total"
      }
    },
    "ds_kpi_users": {
      "type": "ds.search",
      "name": "Distinct Users",
      "options": {
        "query": "index=fake_tshrt demo_id exfil | where isnotnull(user) | stats dc(user) as total"
      }
    },
    "ds_attack_flow_sankey": {
      "type": "ds.search",
      "name": "Attack Flow -- Threat Actor to Targets",
      "options": {
        "query": "| makeresults | eval data=\"185.220.101.42,Port Scanning,757|185.220.101.42,Phishing,6|Phishing,jessica.brown (ATL),2|jessica.brown (ATL),Lateral Movement,30|Lateral Movement,alex.miller (BOS),30|alex.miller (BOS),SharePoint Downloads,265|alex.miller (BOS),AWS S3 Exfil,21|alex.miller (BOS),Google Drive Exfil,15|alex.miller (BOS),C2 Upload,8|SharePoint Downloads,Data Exfiltrated,265|AWS S3 Exfil,Data Exfiltrated,21|Google Drive Exfil,Data Exfiltrated,15|C2 Upload,185.220.101.42,8\" | makemv delim=\"|\" data | mvexpand data | rex field=data \"(?<source>[^,]+),(?<target>[^,]+),(?<value>\\d+)\" | eval value=tonumber(value) | table source target value"
      }
    },
    "ds_attack_linkgraph": {
      "type": "ds.search",
      "name": "Attack Journey -- 6-Phase Kill Chain",
      "options": {
        "query": "| makeresults count=35 | streamstats count as row | eval Recon=case(row=1,\"Threat actor 185.220.101.42 Frankfurt\",row=2,\"757 port scans: MySQL, RDP, SSH, SMB\",row=3,\"28 failed logons (EventID 4625)\",row=4,\"6 phishing emails from rnicrosoft.com\",row=5,\"DNS lookups against target domains\",1=1,\"\") | eval Initial_Access=case(row>=1 AND row<=6,\"Spearphishing via rnicrosoft-security.com\",row=7,\"jessica.brown clicks phishing link\",row=8,\"Encoded PowerShell downloads C2 agent\",row=9,\"C2 callback to 185.220.101.42:443\",row=10,\"O365 inbox rule created for persistence\",1=1,\"\") | eval Lateral_Movement=case(row>=6 AND row<=11,\"jessica.brown compromised (Atlanta)\",row=12,\"Email forwarding to protonmail.com\",row=13,\"AD recon: net view, net group admins\",row=14,\"Password reset for alex.miller account\",row=15,\"MFA auth method deleted + re-registered\",row=16,\"Cross-site pivot ATL 10.20 to BOS 10.10\",row=17,\"EntraID sign-in from Frankfurt 03:25\",1=1,\"\") | eval Persistence=case(row>=11 AND row<=18,\"alex.miller compromised (Boston)\",row=19,\"Scheduled task: WindowsHealthCheck\",row=20,\"AWS IAM user svc-datasync created\",row=21,\"AdminAccess policy attached svc-datasync\",row=22,\"GCP service account key exported\",row=23,\"Entra ID app consent: DataSync Service\",row=24,\"GetSecretValue prod/database/credentials\",1=1,\"\") | eval Data_Staging=case(row>=18 AND row<=25,\"Cloud + endpoint access established\",row=26,\"265 SharePoint files downloaded via O365\",row=27,\"7z.exe compresses data_batch_1-4.zip\",row=28,\"S3 bucket listing via svc-datasync\",row=29,\"AWS secrets + DB credentials harvested\",1=1,\"\") | eval Exfiltration=case(row>=25 AND row<=30,\"265 files + secrets staged for exfil\",row=31,\"AWS S3 GetObject x26 (03:00-05:30)\",row=32,\"rclone sync to gdrive:backup/finance/\",row=33,\"curl POST 185.220.101.42/upload x8\",row=34,\"Exfil across 3 nights Jan 12-14\",row=35,\"Cleanup: del /q data_batch*.zip\",1=1,\"\") | eval Response=case(row=30,\"INC0000218 P1: Unusual data transfer\",row=31,\"CHG0000032: Isolate endpoints\",row=32,\"INC0000219: alex.miller compromised\",row=33,\"All credentials rotated + MFA reset\",row=34,\"Endpoints isolated via Meraki policy\",row=35,\"Backdoor accts deleted AWS+GCP+Entra\",1=1,\"\") | where Recon!=\"\" OR Initial_Access!=\"\" OR Lateral_Movement!=\"\" OR Persistence!=\"\" OR Data_Staging!=\"\" OR Exfiltration!=\"\" OR Response!=\"\" | table Recon Initial_Access Lateral_Movement Persistence Data_Staging Exfiltration Response"
      }
    },
    "ds_attack_timeline": {
      "type": "ds.search",
      "name": "14-Day Attack Timeline by Source Category",
      "options": {
        "query": "index=fake_tshrt demo_id exfil | eval source_cat=case(match(sourcetype,\"cisco:asa\"), \"Firewall (ASA)\", match(sourcetype,\"aws\"), \"AWS\", match(sourcetype,\"google:gcp\"), \"GCP Audit\", match(sourcetype,\"azure:aad\"), \"Entra ID\", match(sourcetype,\"o365:management\"), \"M365 Activity\", match(sourcetype,\"o365:reporting\"), \"Exchange\", match(sourcetype,\"Sysmon\"), \"Sysmon\", match(sourcetype,\"WinEventLog\"), \"Windows Events\", match(sourcetype,\"umbrella\"), \"Secure Access\", match(sourcetype,\"meraki\"), \"Meraki Network\", match(sourcetype,\"cisco:aci\"), \"ACI\", match(sourcetype,\"cisco:ios\"), \"Catalyst\", match(sourcetype,\"servicenow\"), \"ServiceNow\", match(sourcetype,\"mssql\"), \"MSSQL\", match(sourcetype,\"cisco:webex\"), \"Webex\", match(sourcetype,\"cpu|interfaces|iostat|vmstat\"), \"Linux Metrics\", 1=1, \"Other\") | timechart span=1d count by source_cat"
      }
    },
    "ds_recon_port_scans": {
      "type": "ds.search",
      "name": "Reconnaissance Port Scan Targets",
      "options": {
        "query": "index=fake_tshrt demo_id exfil sourcetype=\"FAKE:cisco:asa\" earliest=\"01/01/2026:00:00:00\" latest=\"01/05/2026:00:00:00\" | where isnotnull(dest_port) | stats count by dest_port | eval service=case(dest_port=\"3306\",\"MySQL (3306)\",dest_port=\"23\",\"Telnet (23)\",dest_port=\"5432\",\"PostgreSQL (5432)\",dest_port=\"1433\",\"MSSQL (1433)\",dest_port=\"22\",\"SSH (22)\",dest_port=\"445\",\"SMB (445)\",dest_port=\"3389\",\"RDP (3389)\",1=1,\"Port \".dest_port) | sort -count | head 10 | rename service as \"Target Service\" count as \"Scan Attempts\""
      }
    },
    "ds_recon_timeline": {
      "type": "ds.search",
      "name": "Reconnaissance Scan Volume Over Time",
      "options": {
        "query": "index=fake_tshrt demo_id exfil sourcetype=\"FAKE:cisco:asa\" earliest=\"01/01/2026:00:00:00\" latest=\"01/05/2026:00:00:00\" | timechart span=4h count"
      }
    },
    "ds_phishing_emails": {
      "type": "ds.search",
      "name": "Phishing Email Evidence",
      "options": {
        "query": "index=fake_tshrt demo_id exfil sourcetype=\"FAKE:o365:reporting:messagetrace\" | eval day=strftime(_time,\"%Y-%m-%d %H:%M\") | table day SenderAddress RecipientAddress Subject Status | sort day | rename day as \"Time\" SenderAddress as \"From\" RecipientAddress as \"To\""
      }
    },
    "ds_initial_o365": {
      "type": "ds.search",
      "name": "Initial Access O365 Activity Day 5",
      "options": {
        "query": "index=fake_tshrt demo_id exfil sourcetype=\"FAKE:o365:management:activity\" earliest=\"01/05/2026:00:00:00\" latest=\"01/06/2026:00:00:00\" | eval day=strftime(_time,\"%Y-%m-%d %H:%M\") | table day Operation user file_name | sort day | rename day as \"Time\" file_name as \"File\""
      }
    },
    "ds_network_sankey": {
      "type": "ds.search",
      "name": "Network Traffic Flow -- ASA by Subnet",
      "options": {
        "query": "index=fake_tshrt demo_id exfil sourcetype=\"FAKE:cisco:asa\" | where isnotnull(src) AND isnotnull(dest) | eval src_net=case(match(src,\"^10\\.10\\.\"), \"Boston (10.10.x)\", match(src,\"^10\\.20\\.\"), \"Atlanta (10.20.x)\", match(src,\"^10\\.30\\.\"), \"Austin (10.30.x)\", match(src,\"^172\\.16\\.\"), \"DMZ\", match(src,\"^185\\.220\\.\"), \"Threat Actor\", 1=1, \"External\") | eval dest_net=case(match(dest,\"^10\\.10\\.\"), \"Boston (10.10.x)\", match(dest,\"^10\\.20\\.\"), \"Atlanta (10.20.x)\", match(dest,\"^10\\.30\\.\"), \"Austin (10.30.x)\", match(dest,\"^172\\.16\\.\"), \"DMZ\", match(dest,\"^185\\.220\\.\"), \"Threat Actor\", 1=1, \"External\") | stats count as value by src_net dest_net | rename src_net as source dest_net as target | sort -value"
      }
    },
    "ds_lateral_entraid": {
      "type": "ds.search",
      "name": "Lateral Movement Entra ID Events",
      "options": {
        "query": "index=fake_tshrt demo_id exfil sourcetype=\"FAKE:azure:aad:*\" earliest=\"01/06/2026:00:00:00\" latest=\"01/09/2026:00:00:00\" | eval day=strftime(_time,\"%Y-%m-%d %H:%M\") | table day sourcetype operationName user src properties.riskLevel | sort day | rename day as \"Time\" sourcetype as \"Source\" operationName as \"Operation\" properties.riskLevel as \"Risk\""
      }
    },
    "ds_persist_aws": {
      "type": "ds.search",
      "name": "Persistence AWS CloudTrail Activity",
      "options": {
        "query": "index=fake_tshrt demo_id exfil sourcetype=\"FAKE:aws:cloudtrail\" earliest=\"01/09/2026:00:00:00\" latest=\"01/12/2026:00:00:00\" NOT eventName=PutEvaluations | eval day=strftime(_time,\"%Y-%m-%d %H:%M\") | eval detail=coalesce(requestParameters.userName, requestParameters.policyArn, requestParameters.secretId, \"\") | table day eventName user detail src | sort day | rename day as \"Time\" eventName as \"Event\" user as \"User\" detail as \"Detail\" src as \"Source IP\""
      }
    },
    "ds_persist_consent": {
      "type": "ds.search",
      "name": "Persistence Entra ID Audit Actions",
      "options": {
        "query": "index=fake_tshrt demo_id exfil sourcetype=\"FAKE:azure:aad:audit\" | eval day=strftime(_time,\"%Y-%m-%d %H:%M\") | table day operationName user properties.targetResources{}.displayName | sort day | rename day as \"Time\" operationName as \"Operation\" user as \"Initiated By\" properties.targetResources{}.displayName as \"Target\""
      }
    },
    "ds_exfil_o365": {
      "type": "ds.search",
      "name": "Exfiltration M365 File Operations",
      "options": {
        "query": "index=fake_tshrt demo_id exfil sourcetype=\"FAKE:o365:management:activity\" earliest=\"01/12/2026:00:00:00\" latest=\"01/15/2026:00:00:00\" | timechart span=4h count by Operation"
      }
    },
    "ds_exfil_aws_s3": {
      "type": "ds.search",
      "name": "Exfiltration AWS S3 Operations",
      "options": {
        "query": "index=fake_tshrt demo_id exfil sourcetype=\"FAKE:aws:cloudtrail\" earliest=\"01/12/2026:00:00:00\" latest=\"01/15/2026:00:00:00\" NOT eventName=PutEvaluations | timechart span=4h count by eventName"
      }
    },
    "ds_exfil_evidence": {
      "type": "ds.search",
      "name": "Exfiltration Endpoint Process Evidence",
      "options": {
        "query": "index=fake_tshrt demo_id exfil (sourcetype=\"FAKE:WinEventLog\" OR sourcetype=\"FAKE:WinEventLog:Sysmon\") earliest=\"01/12/2026:00:00:00\" latest=\"01/15/2026:00:00:00\" | where isnotnull(CommandLine) OR isnotnull(Image) | eval day=strftime(_time,\"%Y-%m-%d %H:%M\") | table day Image CommandLine user dest | sort day | rename day as \"Time\" Image as \"Process\" CommandLine as \"Command Line\""
      }
    },
    "ds_exfil_risk": {
      "type": "ds.search",
      "name": "Exfiltration Entra ID Risk Detections",
      "options": {
        "query": "index=fake_tshrt demo_id exfil sourcetype=\"FAKE:azure:aad:riskDetection\" earliest=\"01/12/2026:00:00:00\" latest=\"01/15/2026:00:00:00\" | eval day=strftime(_time,\"%Y-%m-%d %H:%M\") | table day user src properties.riskEventType properties.riskLevel properties.location.city | sort day | rename day as \"Time\" user as \"User\" src as \"IP\" properties.riskEventType as \"Risk Type\" properties.riskLevel as \"Level\" properties.location.city as \"City\""
      }
    },
    "ds_response_servicenow": {
      "type": "ds.search",
      "name": "Incident Response ServiceNow Records",
      "options": {
        "query": "index=fake_tshrt demo_id exfil sourcetype=\"FAKE:servicenow:*\" | eval detail=coalesce(close_notes, work_notes, \"\") | eval day=strftime(_time,\"%Y-%m-%d %H:%M\") | table day sourcetype number dv_state short_description dv_assigned_to detail | sort day | rename day as \"Time\" sourcetype as \"Source\" number as \"Ticket\" dv_state as \"State\" short_description as \"Description\" dv_assigned_to as \"Assigned To\" detail as \"Details\""
      }
    },
    "ds_response_entraid": {
      "type": "ds.search",
      "name": "Incident Response Entra ID Actions",
      "options": {
        "query": "index=fake_tshrt demo_id exfil sourcetype=\"FAKE:azure:aad:audit\" | eval day=strftime(_time,\"%Y-%m-%d %H:%M\") | table day operationName user properties.targetResources{}.displayName | sort day | rename day as \"Time\" operationName as \"Action\" user as \"Initiated By\" properties.targetResources{}.displayName as \"Target\""
      }
    },
    "ds_cross_source_matrix": {
      "type": "ds.search",
      "name": "Cross-Source Correlation Matrix",
      "options": {
        "query": "index=fake_tshrt demo_id exfil | eval source_cat=case(match(sourcetype,\"cisco:asa\"), \"ASA\", match(sourcetype,\"aws\"), \"AWS\", match(sourcetype,\"google:gcp\"), \"GCP\", match(sourcetype,\"azure:aad\"), \"EntraID\", match(sourcetype,\"o365:management\"), \"M365\", match(sourcetype,\"o365:reporting\"), \"Exchange\", match(sourcetype,\"Sysmon\"), \"Sysmon\", match(sourcetype,\"WinEventLog\"), \"WinEvent\", match(sourcetype,\"umbrella\"), \"Umbrella\", match(sourcetype,\"meraki\"), \"Meraki\", match(sourcetype,\"cisco:aci\"), \"ACI\", match(sourcetype,\"cisco:ios\"), \"Catalyst\", match(sourcetype,\"servicenow\"), \"SNOW\", match(sourcetype,\"mssql\"), \"MSSQL\", match(sourcetype,\"cisco:webex\"), \"Webex\", match(sourcetype,\"cpu|interfaces|iostat|vmstat\"), \"Linux\", 1=1, \"Other\") | timechart span=1d count by source_cat"
      }
    },
    "ds_mitre_mapping": {
      "type": "ds.search",
      "name": "MITRE ATT&CK Technique Mapping",
      "options": {
        "query": "| makeresults | eval data=\"T1595.001 Port Scanning|1 Reconnaissance|4,T1566.002 Spearphishing|2 Initial Access|1,T1078 Valid Accounts|2 Initial Access|1,T1059.001 PowerShell|2 Initial Access|1,T1114.003 Email Forwarding|3 Lateral Movement|3,T1021 Remote Services|3 Lateral Movement|3,T1078.004 Cloud Accounts|3 Lateral Movement|3,T1087.002 Domain Discovery|3 Lateral Movement|3,T1098.005 MFA Reset|3 Lateral Movement|3,T1136.003 Create Cloud Acct|4 Persistence|3,T1098 Account Manipulation|4 Persistence|3,T1053.005 Scheduled Task|4 Persistence|3,T1560.001 Archive Utility|4 Persistence|2,T1213.002 SharePoint Data|5 Exfiltration|3,T1567.002 Cloud Exfil|5 Exfiltration|3,T1041 C2 Exfil|5 Exfiltration|3,T1537 Cloud Transfer|5 Exfiltration|3,T1070.004 File Deletion|5 Exfiltration|3\" | makemv delim=\",\" data | mvexpand data | rex field=data \"(?<technique>[^|]+)\\|(?<tactic>[^|]+)\\|(?<days>\\d+)\" | eval days=tonumber(days) | chart max(days) over technique by tactic | fields technique \"1 Reconnaissance\" \"2 Initial Access\" \"3 Lateral Movement\" \"4 Persistence\" \"5 Exfiltration\""
      }
    }
  },
  "visualizations": {
    "viz_header_md": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "# Scenario -- Data Exfiltration (APT)\n\n**demo_id:** `exfil` | **Category:** Security -- Advanced Persistent Threat | **Duration:** 14 days (Jan 1-14, 2026) | **Severity:** Critical\n\n**Threat Actor:** 185.220.101.42 (Frankfurt, Germany | AS205100) -> **Initial Compromise:** Jessica Brown (IT Admin, Atlanta) -> **Primary Target:** Alex Miller (Sr. Financial Analyst, Boston)\n\nExternal threat actor conducts a 14-day APT campaign: port scanning and phishing (Days 1-4), credential harvesting (Day 5), lateral movement ATL->BOS (Days 6-8), cloud persistence via backdoor accounts (Days 9-11), and multi-channel data exfiltration via S3, Google Drive, and C2 upload (Days 12-14).",
        "fontColor": "#C3CBD4",
        "backgroundColor": "#13141A"
      }
    },
    "viz_kpi_events": {
      "type": "splunk.singlevalue",
      "title": "Total Events",
      "dataSources": {
        "primary": "ds_kpi_events"
      },
      "options": {
        "majorValue": "> primary | seriesByName('total') | lastPoint()",
        "majorColor": "#DC4E41",
        "backgroundColor": "#1A1015",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_sourcetypes": {
      "type": "splunk.singlevalue",
      "title": "Sourcetypes",
      "dataSources": {
        "primary": "ds_kpi_sourcetypes"
      },
      "options": {
        "majorValue": "> primary | seriesByName('total') | lastPoint()",
        "majorColor": "#7B56DB",
        "backgroundColor": "#1A1520",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_hosts": {
      "type": "splunk.singlevalue",
      "title": "Affected Hosts",
      "dataSources": {
        "primary": "ds_kpi_hosts"
      },
      "options": {
        "majorValue": "> primary | seriesByName('total') | lastPoint()",
        "majorColor": "#009CEB",
        "backgroundColor": "#101A1F",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_users": {
      "type": "splunk.singlevalue",
      "title": "Affected Users",
      "dataSources": {
        "primary": "ds_kpi_users"
      },
      "options": {
        "majorValue": "> primary | seriesByName('total') | lastPoint()",
        "majorColor": "#F8BE34",
        "backgroundColor": "#1A1A10",
        "sparklineDisplay": "off"
      }
    },
    "viz_attack_flow_sankey": {
      "type": "splunk.sankey",
      "title": "Attack Flow -- Threat Actor -> Compromise -> Exfiltration",
      "dataSources": {
        "primary": "ds_attack_flow_sankey"
      },
      "options": {
        "linkColorMode": "source",
        "backgroundColor": "#13141A"
      }
    },
    "viz_attack_linkgraph": {
      "type": "splunk.linkgraph",
      "title": "Attack Journey -- Kill Chain (Recon -> Access -> Lateral Move -> Persist -> Stage -> Exfil -> Response)",
      "dataSources": {
        "primary": "ds_attack_linkgraph"
      },
      "options": {
        "fieldOrder": [
          "Recon",
          "Initial_Access",
          "Lateral_Movement",
          "Persistence",
          "Data_Staging",
          "Exfiltration",
          "Response"
        ],
        "nodeColor": "#1E3A5F",
        "nodeHighlightColor": "#DC4E41",
        "nodeTextColor": "#E0E4E8",
        "nodeTextHighlightColor": "#FFFFFF",
        "linkColor": "#F8BE34",
        "linkWidth": 3,
        "nodeWidth": 250,
        "nodeHeight": 50,
        "nodeSpacingX": 50,
        "nodeSpacingY": 10,
        "showNodeCounts": true,
        "showValueCounts": true,
        "resultLimit": 60,
        "backgroundColor": "#13141A"
      }
    },
    "viz_attack_timeline": {
      "type": "splunk.area",
      "title": "14-Day Attack Timeline -- All Sources",
      "dataSources": {
        "primary": "ds_attack_timeline"
      },
      "options": {
        "stackMode": "stacked",
        "areaOpacity": 0.7,
        "legendDisplay": "right",
        "nullValueDisplay": "zero",
        "backgroundColor": "#13141A",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Events / day",
        "yAxisTitleVisibility": "show",
        "yAxisAbbreviation": "auto",
        "seriesColors": [
          "#DC4E41",
          "#7B56DB",
          "#53A051",
          "#00D2FF",
          "#009CEB",
          "#F8BE34",
          "#F1813F",
          "#00CDAF",
          "#FF677B",
          "#AE8CFF"
        ]
      },
      "showProgressBar": true,
      "showLastUpdated": true
    },
    "viz_phase1_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "## Phase 1: Reconnaissance -- Days 1-4 (Jan 1-4)\n**MITRE ATT&CK:** T1595.001 (Active Scanning: Port Scanning) | T1598 (Phishing for Information)\n\nThreat actor at **185.220.101.42** (Frankfurt, Germany) conducts aggressive port scanning against public-facing infrastructure. Over 690 firewall deny events logged as the attacker probes database and remote access ports (MySQL 3306, Telnet 23, PostgreSQL 5432, MSSQL 1433). This reconnaissance maps the target network topology before initial access.",
        "fontColor": "#F8BE34",
        "backgroundColor": "#13141A"
      }
    },
    "viz_recon_ports": {
      "type": "splunk.column",
      "title": "Port Scan Targets -- Top Services",
      "dataSources": {
        "primary": "ds_recon_port_scans"
      },
      "options": {
        "seriesColors": [
          "#F8BE34"
        ],
        "backgroundColor": "#13141A",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Scan Attempts",
        "yAxisTitleVisibility": "show",
        "dataValuesDisplay": "all",
        "legendDisplay": "off"
      },
      "showProgressBar": true
    },
    "viz_recon_timeline": {
      "type": "splunk.area",
      "title": "Scan Volume Over Time (4h buckets)",
      "dataSources": {
        "primary": "ds_recon_timeline"
      },
      "options": {
        "areaOpacity": 0.5,
        "seriesColors": [
          "#F8BE34"
        ],
        "backgroundColor": "#13141A",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Events",
        "yAxisTitleVisibility": "show",
        "legendDisplay": "off"
      },
      "showProgressBar": true
    },
    "viz_phase2_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "## Phase 2: Initial Access -- Day 5 (Jan 5)\n**MITRE ATT&CK:** T1566.002 (Phishing: Spearphishing Link) | T1078 (Valid Accounts) | T1114.003 (Email Forwarding Rule)\n\nSpearphishing email delivered to **Jessica Brown** (IT Admin, Atlanta) from fake domain `rnicrosoft-security.com`. Credentials harvested on click. Attacker sets email forwarding rule to `backup-jessica.brown@protonmail.com` for persistent email access. Multiple O365 events confirm the attacker now has a foothold in the tenant.",
        "fontColor": "#DC4E41",
        "backgroundColor": "#13141A"
      }
    },
    "viz_phishing_emails": {
      "type": "splunk.table",
      "title": "Email Evidence -- Message Trace",
      "dataSources": {
        "primary": "ds_phishing_emails"
      },
      "options": {
        "count": 20,
        "showRowNumbers": false,
        "backgroundColor": "transparent"
      },
      "showProgressBar": true
    },
    "viz_initial_o365": {
      "type": "splunk.table",
      "title": "O365 Activity -- Day 5",
      "dataSources": {
        "primary": "ds_initial_o365"
      },
      "options": {
        "count": 20,
        "showRowNumbers": false,
        "backgroundColor": "transparent"
      },
      "showProgressBar": true
    },
    "viz_phase3_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "## Phase 3: Lateral Movement -- Days 6-8 (Jan 6-8)\n**MITRE ATT&CK:** T1021 (Remote Services) | T1078.004 (Cloud Accounts) | T1087 (Account Discovery)\n\nUsing Jessica Brown's credentials, the attacker pivots from **Atlanta (10.20.x.x)** to **Boston (10.10.x.x)**. The Sankey diagram shows network traffic flow through the ASA firewall -- note cross-site connections from ATL to BOS. Cloud resource enumeration begins on Day 8 as the attacker discovers AWS and GCP infrastructure.",
        "fontColor": "#009CEB",
        "backgroundColor": "#13141A"
      }
    },
    "viz_network_sankey": {
      "type": "splunk.sankey",
      "title": "Network Traffic Flow -- ASA Firewall by Subnet",
      "dataSources": {
        "primary": "ds_network_sankey"
      },
      "options": {
        "linkColorMode": "source",
        "backgroundColor": "#13141A"
      }
    },
    "viz_lateral_entraid": {
      "type": "splunk.table",
      "title": "Entra ID Sign-ins and Risk Detections -- Days 6-8",
      "dataSources": {
        "primary": "ds_lateral_entraid"
      },
      "options": {
        "count": 15,
        "showRowNumbers": false,
        "backgroundColor": "transparent"
      },
      "showProgressBar": true
    },
    "viz_phase4_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "## Phase 4: Persistence -- Days 9-11 (Jan 9-11)\n**MITRE ATT&CK:** T1136.003 (Create Cloud Account) | T1098 (Account Manipulation) | T1071 (Application Layer Protocol)\n\nThe attacker establishes persistence across cloud platforms. In AWS, **alex.miller** creates backdoor IAM user `svc-datasync` with admin policies. In Entra ID, admin consent is granted to malicious app **DataSync Service** with `Mail.Read` and `Files.Read.All` permissions. GCP service accounts show unusual storage operations. C2 beacons maintain communication with 185.220.101.42.",
        "fontColor": "#7B56DB",
        "backgroundColor": "#13141A"
      }
    },
    "viz_persist_aws": {
      "type": "splunk.table",
      "title": "AWS CloudTrail -- IAM and S3 Activity",
      "dataSources": {
        "primary": "ds_persist_aws"
      },
      "options": {
        "count": 15,
        "showRowNumbers": false,
        "backgroundColor": "transparent"
      },
      "showProgressBar": true
    },
    "viz_persist_consent": {
      "type": "splunk.table",
      "title": "Entra ID Audit -- Persistence Actions",
      "dataSources": {
        "primary": "ds_persist_consent"
      },
      "options": {
        "count": 10,
        "showRowNumbers": false,
        "backgroundColor": "transparent"
      },
      "showProgressBar": true
    },
    "viz_phase5_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "## Phase 5: Exfiltration -- Days 12-14 (Jan 12-14)\n**MITRE ATT&CK:** T1567.002 (Exfil to Cloud Storage) | T1041 (Exfil Over C2) | T1213.002 (Data from SharePoint) | T1070.004 (File Deletion)\n\nMulti-channel data exfiltration during nighttime hours (01:00-05:00 UTC). **188 files** downloaded from SharePoint via M365. Data staged, compressed, and exfiltrated via three channels: (1) **rclone** to Google Drive, (2) **curl** to C2 server 185.220.101.42/upload, (3) **AWS S3** PutObject. Post-exfil cleanup: `del /q data_batch_*.zip`.",
        "fontColor": "#DC4E41",
        "backgroundColor": "#13141A"
      }
    },
    "viz_exfil_o365": {
      "type": "splunk.column",
      "title": "M365 File Operations -- Days 12-14",
      "dataSources": {
        "primary": "ds_exfil_o365"
      },
      "options": {
        "stackMode": "stacked",
        "seriesColors": [
          "#DC4E41",
          "#F8BE34",
          "#7B56DB",
          "#009CEB",
          "#53A051"
        ],
        "backgroundColor": "#13141A",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Events",
        "yAxisTitleVisibility": "show",
        "legendDisplay": "bottom"
      },
      "showProgressBar": true
    },
    "viz_exfil_aws": {
      "type": "splunk.column",
      "title": "AWS S3 Exfiltration -- 3-Night Pattern",
      "dataSources": {
        "primary": "ds_exfil_aws_s3"
      },
      "options": {
        "seriesColors": [
          "#7B56DB"
        ],
        "backgroundColor": "#13141A",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "GetObject Calls",
        "yAxisTitleVisibility": "show",
        "legendDisplay": "off",
        "nullValueDisplay": "zero"
      },
      "showProgressBar": true
    },
    "viz_exfil_evidence": {
      "type": "splunk.table",
      "title": "Endpoint Evidence -- Process Execution",
      "dataSources": {
        "primary": "ds_exfil_evidence"
      },
      "options": {
        "count": 20,
        "showRowNumbers": false,
        "backgroundColor": "transparent"
      },
